#include <stdio.h>
#include <string.h>

int maxTruthSpeakers(int n, char statements[][1001]) {
    int maxCount = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        int count = 0;
        int valid = 1;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                count++;
                for (int j = 0; j < n; j++) {
                    if (statements[i][j] == 'T' && (mask & (1 << j)) == 0) {
                        valid = 0;
                        break;
                    }
                    if (statements[i][j] == 'F' && (mask & (1 << j)) != 0) {
                        valid = 0;
                        break;
                    }
                }
            }
        }
        if (valid) {
            maxCount = (maxCount > count) ? maxCount : count;
        }
    }
    return maxCount;
}

int main() {
    int n;
    scanf("%d", &n);
    char statements[1001][1001];
    for (int i = 0; i < n; i++) {
        scanf("%s", statements[i]);
    }
    printf("%d\n", maxTruthSpeakers(n, statements));
    return 0;
}

